blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie nauczysz się <strong>podstawowej kolejności słów</strong> w angielskich zdaniach twierdzących: struktury S–V–O, układu przysłówków częstotliwości oraz okoliczności czasu i miejsca.",
    "rules": [
        {
            "label": "Podstawowe struktura",
            "color": "emerald",
            "text": "<strong>Podmiot + Czasownik + Dopełnienie</strong> to podstawa zdania w języku angielskim:",
            "example": "Ona czyta książki."
        },
        {
            "label": "Przysłówki częstotliwości",
            "color": "blue",
            "text": "<strong>Zawsze, często, czasami, nigdy</strong> nie stoją przed głównym czasownik:",
            "example": "Zawsze piję herbatę rano."
        },
        {
            "label": "Czas i miejsce",
            "color": "amber",
            "text": "<strong>Miejsce + czas</strong> zwykle na końcu zdania:",
            "example": "W każdą niedzielę gramy w parku w piłkę nożną."
        }
    ]
}

{
    "title": "1. Struktura S–V–O (Podmiot–Czasownik–Dopełnienie)",
    "intro": "Zdanie twierdzące w języku angielskim zbudowane jest według schematu:",
    "items": [
        {
            "label": "S — Podmiot",
            "title": "Podmiot",
            "subtitle": "Kto lub co wykonuje czynność (ja, ty, ona, Tomek, pies)"
        },
        {
            "label": "V — Czasownik",
            "title": "Czasownik",
            "subtitle": "Działanie lub stan (czytaj, jedz, jest, masz)"
        },
        {
            "label": "O — Obiekt",
            "title": "Załącznik",
            "subtitle": "Do kogo/co skierowana jest akcja (książka, kawa, on)"
        }
    ]
}

{
    "title": "2. Przysłówki częstotliwości",
    "sections": [
        {
            "label": "Przed czasownikiem głównym",
            "color": "emerald",
            "description": "Przysłówki <strong>zawsze, zwykle, często, czasami, rzadko, nigdy</strong> są umieszczane <strong>przed</strong> czasownikiem głównym.",
            "examples": [
                {
                    "en": "Ona zawsze je śniadanie.",
                    "ua": "Ona zawsze je śniadanie."
                },
                {
                    "en": "Często chodzę do siłownia.",
                    "ua": "Często chodzę na siłownię."
                },
                {
                    "en": "Nigdy nie piją kawy.",
                    "ua": "Nigdy nie piją kawy."
                }
            ]
        },
        {
            "label": "Po czasowniku TO BE",
            "color": "sky",
            "description": "Jeśli czasownik <strong>być</strong> (am, is, are, was, was, były) jest w zdaniu, przysłówek częstotliwości jest umieszczony <strong>po</strong> nim.",
            "examples": [
                {
                    "en": "On zawsze się spóźnia.",
                    "ua": "On zawsze się spóźnia."
                },
                {
                    "en": "Ona zwykle jest szczęśliwa.",
                    "ua": "Ona zwykle jest szczęśliwa."
                },
                {
                    "en": "Oni nigdy się nie nudzą.",
                    "ua": "Nigdy się nie nudzą."
                }
            ]
        },
        {
            "label": "Czasami / Zwykle na początku",
            "color": "amber",
            "description": "Niektóre przysłówki (<strong>czasami, zwykle, często</strong>) mogą występować na początku zdania dla podkreślenia.",
            "examples": [
                {
                    "en": "Czasami czytałem wcześniej łóżka.",
                    "ua": "Czasami czytam przed pójściem spać."
                },
                {
                    "en": "Zwykle jemy kolację o 7.",
                    "ua": "Zwykle jemy kolację o 7."
                }
            ],
            "note": "<strong>Zawsze</strong> i <strong>nigdy</strong> rzadko są umieszczane na początku zdanie."
        }
    ]
}

{
    "title": "3. Przysłówki czasu)",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Przysłówki czasu (<strong>wczoraj, każdego dnia, o 7:00, w zeszłym tygodniu</strong>) są zwykle <strong>na końcu</strong> zdania.",
            "examples": [
                {
                    "en": "Budzę się o 6:00 godzina.",
                    "ua": "Budzę się o szóstej."
                },
                {
                    "en": "Ona codziennie uczy się angielskiego.",
                    "ua": "Вона вчить англійську щодня."
                },
                {
                    "en": "We went to the cinema last night.",
                    "ua": "Ми ходили в кіно вчора ввечері."
                }
            ]
        },
        {
            "label": "На початку речення",
            "color": "sky",
            "description": "Для акценту обставини часу можна поставити <strong>на початку</strong>.",
            "examples": [
                {
                    "en": "Wczoraj spotkałem starego znajomego.",
                    "ua": "Wczoraj spotkałem starego przyjaciela."
                },
                {
                    "en": "Codziennie rano biegała w parku.",
                    "ua": "Każdego ranka biega po parku."
                }
            ]
        }
    ]
}

{
    "title": "4. Umieszczaj przysłówki",
    "sections": [
        {
            "label": "Po czasowniku / przysłówku",
            "color": "emerald",
            "description": "Umieszczaj przysłówki (<strong>w szkole, w parku, w domu</strong>) <strong>po czasowniku</strong> lub <strong>przysłówku</strong>.",
            "examples": [
                {
                    "en": "Pracuje w firmie biuro.",
                    "ua": "Pracuje w biurze."
                },
                {
                    "en": "Ona czyta książki w swoim pokoju.",
                    "ua": "Czyta książki w swoim pokoju."
                }
            ]
        },
        {
            "label": "Miejsce przed czasem",
            "color": "sky",
            "description": "Jeśli jest miejsce i czas, kolejność jest następująca: Czas</strong>.",
            "examples": [
                {
                    "en": "W niedziele jemy obiad w domu.",
                    "ua": "W niedziele jemy obiad w domu."
                },
                {
                    "en": "Dzieci bawią się w parku każdego popołudnia.",
                    "ua": "Dzieci bawią się w parku codziennie popołudnie."
                }
            ]
        }
    ]
}

{
    "title": "5. Pełna struktura zdania",
    "intro": "Pełna kolejność elementów w zdaniu twierdzącym:",
    "rows": [
        {
            "en": "Temat",
            "ua": "Temat",
            "note": "Ona, Tom, Oni"
        },
        {
            "en": "Przysłówek Częstotliwość",
            "ua": "Częstotliwość przysłówka",
            "note": "zawsze, często, nigdy (przed czasownikiem głównym)"
        },
        {
            "en": "Czasownik",
            "ua": "Czasownik",
            "note": "czyta, je, bawi się"
        },
        {
            "en": "Obiekt",
            "ua": "Dodatek",
            "note": "książki, kawa, piłka nożna"
        },
        {
            "en": "Miejsce",
            "ua": "Miejsce",
            "note": "w szkole, w parku"
        },
        {
            "en": "Czas",
            "ua": "Czas",
            "note": "codziennie, wczoraj, o 7 godzina"
        }
    ],
    "warning": "📌 Formuła: <strong>S + (Adv) + V + O + Miejsce + Czas</strong>"
}

{
    "title": "6. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zmiana kolejności S–V–O pod wpływem ukraińskiego.",
            "wrong": "Czyta książki codziennie.",
            "right": "​​​​ <span class="font-mono">Czyta książek każdego dnia.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Nieprawidłowe umieszczenie przysłówka częstotliwości.",
            "wrong": "Ona zawsze czyta książki.",
            "right": "​​​​​​​​ end."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Час посередині речення замість кінця.",
            "wrong": "Idę codziennie do szkoły.",
            "right": "​​​​ <span class="font-mono">Codziennie chodzę do szkoły.</span>"
        }
    ]
}

{
    "title": "7. Krótkie streszczenie",
    "items": [
        "Struktura podstawowa: <strong>S + V + O</strong> (podmiot + czasownik + dopełnienie).",
        "Przysłówki częstotliwości (<em>zawsze, często, nigdy</em>) — <strong>przed czasownikiem głównym</strong> lub <strong>po to być</strong>.",
        "Okoliczności czasowe (<em>wczoraj, codziennie</em>) – zwykle <strong>na końcu</strong> zdania.",
        "Okoliczności miejsca (<em>w domu, w parku</em>) – po przysłówku, <strong>przed czas</strong>.[[[CODX_30]]]Wzór: <strong>S + (Adv) + V + O + Miejsce + Czas</strong>.",
        "Формула: <strong>S + (Adv) + V + O + Place + Time</strong>."
    ]
}

{
    "title": "8. Praktyka",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz zdanie z odpowiednią kolejnością słów.",
    "selects": [
        {
            "label": "a) Ona zawsze pije kawę. / b) Zawsze pije kawę.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Codziennie chodzę do pracy. / b) Codziennie chodzę do pracy.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) On w biurze pracuje. / b) Pracuje w biurze.",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Ułóż słowa w odpowiedniej kolejności",
    "input_intro": "Ułóż zdania z podanych słowa.",
    "inputs": [
        {
            "before": "(ona / czyta / książki / często)",
            "after": " →"
        },
        {
            "before": "(codziennie rano / ja / śniadanie / jem)",
            "after": " → [[CODX_SEG_16]]](w domu / w niedziele / my / obiad / mieć)"
        },
        {
            "before": "(at home / on Sundays / we / dinner / have)",
            "after": " →"
        }
    ],
    "rephrase_title": " Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd w kolejności wyrazów.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Gra w piłkę nożną co dziennie.",
            "example_target": "On codziennie gra w piłkę nożną."
        },
        {
            "original": "1. Ona zawsze czyta książki wieczorem.",
            "placeholder": "Popraw kolejność słów"
        },
        {
            "original": "2. Co tydzień chodzimy do supermarketu.",
            "placeholder": "Poprawna kolejność słów"
        }
    ]
}

{
    "title": "Inne strony dotyczące podstawowej gramatyki",
    "items": [
        {
            "label": "Kolejność słów – kolejność słów (bieżąca)",
            "current": true
        }
    ]
}
